head.script:
scwin.PG_EVENT_FG = 0;
scwin.SAVE_EVENT = 1;
scwin.hid_shpCoClntNo = "";
scwin.hid_lineCd = "";
scwin.txt_sealImg = "";
scwin.txt_sealImg2 = "";
scwin.txt_sealImg3 = "";
scwin.g_accdNo = "";

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let str = "[[[[" + dataList.id + "]]]]]\n";
        let colInfos = dataList.getColumnIds();
        for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
            for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
                str += "[" + colInfos[dsCol] + "] " + dataList.getCellData(dsRow, colInfos[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.onpageload = async function() {
    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableBtn([btn_Update, btn_Save, btn_Delete]);
    $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);
    await $c.sbm.execute(sbm_LkEqNrm);
};

scwin.onUdcCompleted = async function() {
};

scwin.f_createHeader_ForUpload = async function() {
};

scwin.f_Create = async function() {
    ds_out.insertRow(ds_out.getRowCount());
    let rowPos = ds_out.getRowPosition();
    ds_out.setCellData(rowPos, "ocShipYn", "1");
    ds_out.setCellData(rowPos, "useYn", "1");

    $c.gus.cfEnableKeyData();
    $c.gus.cfEnableObjects([img_clntPop, img_linePop, btn_Update, btn_Save, btn_Delete, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

    ds_outEq.removeAll();
    ds_outEqHold.removeAll();
    ds_attach.removeAll();
    ds_attach2.removeAll();
    gr_outEq.setColumnReadOnly("vsslEqNo", false);
    gr_outEq.setColumnReadOnly("vsslEqNm", false);
    gr_outEq.setColumnReadOnly("eqKndCd", false);
    gr_outEq.setColumnReadOnly("eqNrmCd", false);
};

scwin.f_Save = async function() {
    if (ds_out.isUpdated() == false && ds_outEq.isUpdated() == false && ds_outEqHold.isUpdated() == false && ds_attach.isUpdated() == false && ds_attach2.isUpdated() == false) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["선박정보"]);
        return;
    }

    let chk = await $c.gus.cfValidate([oRecevInfo]);
    if (chk == false) {
        return;
    }

    let rowPos = ds_out.getRowPosition();
    let strCallsignCd = ds_out.getCellData(rowPos, "callsignCd");

    for (let i = 0; i < ds_out.getRowCount(); i++) {
        if (i != rowPos && strCallsignCd == ds_out.getCellData(i, "callsignCd")) {
            await $c.win.alert("선박호출번호가 중복되었습니다.");
            return;
        }
    }

    for (let idx = 0; idx < ds_outEqHold.getRowCount(); idx++) {
        if (ds_outEqHold.getCellData(idx, "holdNo") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["HOLD번호"]);
            return;
        }
    }

    scwin.PG_EVENT_FG = scwin.SAVE_EVENT;

    await $c.sbm.execute(sbm_save);

    gr_outEq.setColumnReadOnly("vsslEqNo", true);
    gr_outEq.setColumnReadOnly("vsslEqNm", true);
    gr_outEq.setColumnReadOnly("eqKndCd", true);
    gr_outEq.setColumnReadOnly("eqNrmCd", true);

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableBtn([btn_Save]);
    $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);
    $c.gus.cfTurnCreateFlag(false);
};

scwin.f_Update = async function() {
    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete]);
    $c.gus.cfEnableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

    gr_outEq.setColumnReadOnly("vsslEqNo", false);
    gr_outEq.setColumnReadOnly("vsslEqNm", false);
    gr_outEq.setColumnReadOnly("eqKndCd", false);
    gr_outEq.setColumnReadOnly("eqNrmCd", false);
};

scwin.f_Delete = async function() {
    let rowPos = ds_out.getRowPosition();
    let v_status = ds_out.getRowStatus(rowPos);

    if (ds_out.getRowCount() == 0 || v_status == "C") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, ["삭제"]);
        return;
    } else {
        let chk = await $c.win.confirm(MSG_CM_CRM_004, ["삭제"]);
        if (chk) {
            ds_out.removeRow(rowPos);
            await $c.sbm.execute(sbm_delete);

            $c.gus.cfTurnCreateFlag(false);

            gr_outEq.setColumnReadOnly("vsslEqNo", true);
            gr_outEq.setColumnReadOnly("vsslEqNm", true);
            gr_outEq.setColumnReadOnly("eqKndCd", true);
            gr_outEq.setColumnReadOnly("eqNrmCd", true);

            $c.gus.cfTurnCreateFlag(false);
        }
    }
};

scwin.f_Retrieve = async function() {
    if (chk_cnd_useYn.getValue() == "" || chk_cnd_useYn.getValue() == null) {
        dma_condition.set("useYn", "1");
    } else {
        dma_condition.set("useYn", "0");
    }

    await $c.sbm.execute(sbm_retrieve);

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableBtn([btn_Save]);
    $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

    gr_outEq.setColumnReadOnly("vsslEqNo", true);
    gr_outEq.setColumnReadOnly("vsslEqNm", true);
    gr_outEq.setColumnReadOnly("eqKndCd", true);
    gr_outEq.setColumnReadOnly("eqNrmCd", true);
};

scwin.f_Submit = async function() {
    if (ds_attach.getRowCount() == 0) {
        scwin.f_createHeader_ForUpload();
    }
    // TODO: cfUploadFile 파일업로드 처리 - WebSquare 파일업로드 UDC로 대체 필요
};

scwin.uploadComplete = async function() {
    fileUploadGDS.sort("fileId", "asc");

    for (let i = 0; i < fileUploadGDS.getRowCount(); i++) {
        ds_attach.insertRow(ds_attach.getRowCount());
        let lastRow = ds_attach.getRowCount() - 1;

        if (ds_attach.getRowCount() != 1) {
            let fltNxtSeq = parseFloat(ds_attach.getCellData(lastRow - 1, "attachFileId")) + 1;
            let strNxtSeq = "000" + fltNxtSeq;
            strNxtSeq = strNxtSeq.substr(strNxtSeq.length - 4, strNxtSeq.length);
            ds_attach.setCellData(lastRow, "attachFileId", strNxtSeq);
        } else {
            ds_attach.setCellData(lastRow, "attachFileId", "0001");
        }

        ds_attach.setCellData(lastRow, "vsslCd", ed_vsslCd.getValue());
        ds_attach.setCellData(lastRow, "attachFileNm", fileUploadGDS.getCellData(i, "filename"));
        ds_attach.setCellData(lastRow, "attachFileDesc", fileUploadGDS.getCellData(i, "filename"));
        ds_attach.setCellData(lastRow, "attachFileSiz", fileUploadGDS.getCellData(i, "fileSize"));
        ds_attach.setCellData(lastRow, "attachFilePath", fileUploadGDS.getCellData(i, "filepath"));
    }
};

scwin.f_AddRowEquipment = async function() {
    let chk = await $c.gus.cfValidate([oRecevInfo]);
    if (chk == false) {
        return;
    }

    ds_outEq.insertRow(ds_outEq.getRowCount());
    let eqRowPos = ds_outEq.getRowPosition();
    let outRowPos = ds_out.getRowPosition();
    ds_outEq.setCellData(eqRowPos, "vsslCd", ds_out.getCellData(outRowPos, "vsslCd"));

    gr_outEq.setColumnReadOnly("vsslEqNo", false);
    gr_outEq.setColumnReadOnly("vsslEqNm", false);
    gr_outEq.setColumnReadOnly("eqKndCd", false);
    gr_outEq.setColumnReadOnly("eqNrmCd", false);
};

scwin.f_DeleteRowEquipment = async function() {
    let eqRowPos = ds_outEq.getRowPosition();
    let v_vsslCd = ds_outEq.getCellData(eqRowPos, "vsslCd");

    for (let i = ds_outEqHold.getRowCount() - 1; i >= 0; i--) {
        if (v_vsslCd == ds_outEqHold.getCellData(i, "vsslCd")) {
            ds_outEqHold.removeRow(i);
        }
    }

    ds_outEq.removeRow(eqRowPos);
};

scwin.f_UndoRowEquipment = async function() {
    let eqRowPos = ds_outEq.getRowPosition();
    let v_vsslCd = ds_outEq.getCellData(eqRowPos, "vsslCd");

    for (let i = 0; i < ds_outEqHold.getRowCount(); i++) {
        if (v_vsslCd == ds_outEqHold.getCellData(i, "vsslCd")) {
            ds_outEqHold.undoRow(i);
        }
    }

    ds_outEq.undoRow(eqRowPos);
};

scwin.f_AddRowHold = async function() {
    let chk = await $c.gus.cfValidate([oRecevInfo]);
    if (chk == false) {
        return;
    }

    if (ed_vsslCd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["선박코드"]);
        return;
    }

    let eqRowPos = ds_outEq.getRowPosition();
    if (ds_outEq.getCellData(eqRowPos, "vsslEqNo") == null || ds_outEq.getCellData(eqRowPos, "vsslEqNo") == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["장비번호"]);
        return;
    }

    ds_outEqHold.insertRow(ds_outEqHold.getRowCount());
    let holdRowPos = ds_outEqHold.getRowPosition();
    ds_outEqHold.setCellData(holdRowPos, "vsslCd", ds_outEq.getCellData(eqRowPos, "vsslCd"));
    ds_outEqHold.setCellData(holdRowPos, "vsslEqNo", ds_outEq.getCellData(eqRowPos, "vsslEqNo"));
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch, row) {
    if (row == null) {
        row = 0;
    }

    switch (disGubun) {
        case 1:
            udc_cnd_shpCoClnt.ilCommonPopUp(scwin.callbackCase1,
                pCode, pName, pClose, null, null, null, null, 'SHP', null, null, null, null, null, 'F', null);
            break;
        case 2:
            udc_cnd_shpCoClnt.ilCommonPopUp(scwin.callbackCase2,
                pCode, pName, pClose, null, null, null, null, 'SHP', null, null, null, null, null, 'F', null);
            break;
        case 3:
            udc_cnd_shpCoClnt.ilCommonPopUp(scwin.callbackCase3,
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, 'F', null);
            break;
        default:
            break;
    }
};

scwin.callbackCase1 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cnd_shpCoClntNo, txt_cnd_shpCoClntNm);
};

scwin.callbackCase2 = async function(rtnList) {
    if (rtnList != null && rtnList.length > 0) {
        scwin.hid_shpCoClntNo = rtnList[0];
        ed_shpCoClntNm.setValue(rtnList[1]);
    }
};

scwin.callbackCase3 = async function(rtnList) {
    if (rtnList != null && rtnList.length > 0) {
        scwin.hid_lineCd = rtnList[0];
        ed_lineNm.setValue(rtnList[1]);
    }
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_FieldClear = async function() {
    $c.gus.cfInitObjects(tbl_search, null);
};

scwin.f_grdHeight = async function(size, objGrd) {
    let strHeight = objGrd.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        objGrd.style.height = intHeight + "px";
    }
};

scwin.f_previewImg = async function(rowNum) {
    let rowIdx = rowNum - 1;
    if (ds_attach2.getCellData(rowIdx, "attachFilePath") != "") {
        if (rowNum == "1" || rowNum == 1) {
            // TODO: preView 이미지 표시 - WebSquare 이미지 컴포넌트로 대체 필요
        } else if (rowNum == "2" || rowNum == 2) {
            // TODO: preView2 이미지 표시
        } else if (rowNum == "3" || rowNum == 3) {
            // TODO: preView3 이미지 표시
        }
    }
};

scwin.f_ZoomIn = async function(row) {
    if (ds_attach2.getRowCount() != 0 && row < ds_attach2.getRowCount()) {
        let rowIdx = row - 1;
        let strParam = $c.gus.cfGetFileURL("", ds_attach2.getCellData(rowIdx, "attachFilePath"));
        await $c.win.openPopup("/ui/lo/comninfomgnt/zoom.xml", {
            width: 840,
            height: 660,
            modal: true,
            data: { imgUrl: strParam }
        });
    }
};

scwin.f_saveImg = async function(obj) {
    scwin.f_createHeader_ForUpload();
    ds_attach2.insertRow(ds_attach2.getRowCount());

    let resultList = await $c.win.openPopup("/ui/lo/comninfomgnt/lo_100_08_01p.xml", {
        width: 650,
        height: 250,
        modal: true,
        data: {}
    });

    if (obj == "1" || obj == 1) {
        if (resultList != null) {
            if (resultList[0] != "" && resultList[0] != "undefined") {
                ds_attach2.setCellData(0, "vsslCd", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFileId", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFilePath", resultList[0]);
                scwin.txt_sealImg = resultList[0];
            }
        }
    } else if (obj == "2" || obj == 2) {
        if (resultList != null) {
            if (resultList[0] != "" && resultList[0] != "undefined") {
                ds_attach2.setCellData(0, "vsslCd", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFileId", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFilePath", resultList[0]);
                scwin.txt_sealImg2 = resultList[0];
            }
        }
    } else if (obj == "3" || obj == 3) {
        if (resultList != null) {
            if (resultList[0] != "" && resultList[0] != "undefined") {
                ds_attach2.setCellData(0, "vsslCd", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFileId", ed_vsslCd.getValue());
                ds_attach2.setCellData(0, "attachFilePath", resultList[0]);
                scwin.txt_sealImg3 = resultList[0];
            }
        }
    }
};

scwin.f_fileSet = async function(row, data) {
    let rowIdx = row - 1;
    let obj = {
        fileName: ds_AccdFile.getCellData(rowIdx, "fileNm"),
        filePath: ds_AccdFile.getCellData(rowIdx, "fileSavePath"),
        accdNo: scwin.g_accdNo
    };

    let resultList = await $c.win.openPopup("/ui/lo/comninfomgnt/tr_510_01_02p.xml", {
        width: 650,
        height: 400,
        modal: true,
        data: obj
    });

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            ds_AccdFile.setCellData(rowIdx, "fileNm", resultList[1]);
            ds_AccdFile.setCellData(rowIdx, "fileSavePath", resultList[0]);
            ds_AccdFile.setCellData(rowIdx, "fileSiz", resultList[2]);
        }
    }
};

scwin.f_SetRowMark = async function(row) {
    if (row == "1" || row == 1) {
        if (ds_attach2.getRowCount() > 0) {
            ds_attach2.removeRow(0);
        }
    } else if (row == "2" || row == 2) {
        if (ds_attach2.getRowCount() > 1) {
            ds_attach2.removeRow(1);
        }
    } else if (row == "3" || row == 3) {
        if (ds_attach2.getRowCount() > 2) {
            ds_attach2.removeRow(2);
        }
    }
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);

    if ($c.gus.cfCheckCreateFlag() == true) {
        $c.gus.cfTurnCreateFlag(false);
    }
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_delete_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004, ["삭제결과"]);

    if ($c.gus.cfCheckCreateFlag() == true) {
        $c.gus.cfTurnCreateFlag(false);
    }
};

scwin.sbm_delete_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowcnt = ds_out.getRowCount();

    if ($c.gus.cfCheckCreateFlag() == true) {
        ds_out.insertRow(ds_out.getRowCount());
        ds_outEq.removeAll();
        ds_outEqHold.removeAll();

        rd_ocShipYn.setValue("1");
        rd_useYn.setValue("1");

        $c.gus.cfEnableObjects([oRecevInfo]);
        $c.gus.cfDisableBtn([btn_Create, btn_Update, btn_Delete]);
        ed_vsslCd.setFocus();
    } else {
        $c.gus.cfShowTotalRows(totalRows1, ds_out.getRowCount());

        if (rowcnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002, ["조회결과"]);

            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtn([btn_Update, btn_Save, btn_Delete]);
        } else {
            dma_conditionDetail.set("vsslCd", ds_out.getCellData(0, "vsslCd"));
            dma_conditionDetail.set("shpCoClntNo", ds_out.getCellData(0, "shpCoClntNo"));

            await $c.sbm.execute(sbm_retrieveFile);
            await $c.sbm.execute(sbm_retrieveFile2);
            await $c.sbm.execute(sbm_retrieveEq);

            $c.gus.cfDisableKey();
            $c.gus.cfDisableObjects([oRecevInfo]);
            $c.gus.cfEnableAllBtn();
            $c.gus.cfDisableBtn([btn_Save]);
        }
    }
};

scwin.sbm_retrieve_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveEq_submitdone = async function(e) {
    $c.gus.cfShowTotalRows(totalRows2, ds_outEq.getRowCount());
};

scwin.sbm_retrieveEq_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveEqHold_submitdone = async function(e) {
};

scwin.sbm_retrieveEqHold_submiterror = async function(e) {
};

scwin.sbm_retrieveFile_submitdone = async function(e) {
    $c.gus.cfShowTotalRows(totalRows4, ds_attach.getRowCount());
};

scwin.sbm_retrieveFile_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveFile2_submitdone = async function(e) {
    let rowcnt = ds_attach2.getRowCount();
    if (rowcnt != 0) {
        for (let i = 1; i <= rowcnt; i++) {
            scwin.f_previewImg(i);
        }
    }
};

scwin.sbm_retrieveFile2_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_LkEqNrm_submitdone = async function(e) {
    $c.gus.cfChangeCdNmFormat(ds_LkEqNrm, "cd", "cdNm");
};

scwin.sbm_LkEqNrm_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_out_oncellclick = async function(rowIndex, columnIndex, columnId) {
    if (ds_outEq.isUpdated() == true || ds_outEqHold.isUpdated() == true || ds_attach.isUpdated() == true || ds_attach2.isUpdated() == true) {
        let chk = await $c.win.confirm(MSG_CM_CRM_015);
        if (chk) {
            await $c.sbm.execute(sbm_save);
        }
    }

    if (ds_out.getRowStatus(rowIndex) == "C") {
        $c.gus.cfEnableKeyData();
        $c.gus.cfEnableAllBtn();
        $c.gus.cfEnableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

        ds_outEq.removeAll();
        ds_outEqHold.removeAll();
        ds_attach.removeAll();
        ds_attach2.removeAll();
        gr_outEq.setColumnReadOnly("vsslEqNo", false);
        gr_outEq.setColumnReadOnly("vsslEqNm", false);
        gr_outEq.setColumnReadOnly("eqKndCd", false);
        gr_outEq.setColumnReadOnly("eqNrmCd", false);
    } else {
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableBtn([btn_Save]);
        $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

        gr_outEq.setColumnReadOnly("vsslEqNo", true);
        gr_outEq.setColumnReadOnly("vsslEqNm", true);
        gr_outEq.setColumnReadOnly("eqKndCd", true);
        gr_outEq.setColumnReadOnly("eqNrmCd", true);

        dma_conditionDetail.set("vsslCd", ds_out.getCellData(rowIndex, "vsslCd"));
        dma_conditionDetail.set("shpCoClntNo", ds_out.getCellData(rowIndex, "shpCoClntNo"));

        await $c.sbm.execute(sbm_retrieveEq);
        await $c.sbm.execute(sbm_retrieveFile);
        await $c.sbm.execute(sbm_retrieveFile2);
    }
};

scwin.gr_outEq_oncellclick = async function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        dma_conditionDetail.set("vsslCd", ds_outEq.getCellData(rowIndex, "vsslCd"));
        dma_condition.set("vsslEqNo", ds_outEq.getCellData(rowIndex, "vsslEqNo"));
    }
};

scwin.ds_out_onrowpositionchange = async function(info) {
    let row = info.oldRowIndex;
    let newRow = info.rowIndex;

    if (ds_out.getCellData(ds_out.getRowPosition(), "vsslCd") == ""
        || ds_out.getCellData(ds_out.getRowPosition(), "vsslNm") == "" && scwin.PG_EVENT_FG != scwin.SAVE_EVENT) {
        let chkValid = await $c.gus.cfValidate([oRecevInfo]);
        if (chkValid) {
            if (ds_out.isUpdated()) {
                let chk = await $c.win.confirm(MSG_CM_CRM_015);
                if (chk) {
                    scwin.f_Save();
                    return;
                } else {
                    $c.gus.cfDisableKeyData();
                    ds_out.undoRow(row);
                    $c.gus.cfDisableBtn([btn_Save]);
                    $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);
                    return;
                }
            }
        } else {
            $c.gus.cfEnableKeyData();
            $c.gus.cfDisableBtn([btn_Save]);
            $c.gus.cfDisableObjects([img_clntPop, img_linePop, btn_fileDel1, btn_fileDel2, btn_fileDel3]);

            ds_outEq.removeAll();
            ds_outEqHold.removeAll();
            return;
        }
    }
};

